// Controlleer of Initialize is geweest:
var tijd_nu = global.get("getTime");
if (tijd_nu == undefined)
    return null;


// hoe laat is het nu?
var tijd_nu = global.get("getTime")();
let tijd_nu_ms = global.get("tijdNaarMs")(tijd_nu);
let meldingstijdGebruiker_ms = global.get("tijdNaarMs")(global.get("TijdOK"));
let beginToonVraag_ms = meldingstijdGebruiker_ms - 120 * 60000;
let overtijd_ms = meldingstijdGebruiker_ms + global.get("MeldPeriodeInMinuten") * 60000;

// Wanneer is het tijd om een vraag te stellen (2 uur voor de aangegeven tijd)?
if ((tijd_nu_ms >= beginToonVraag_ms) &&
    (tijd_nu_ms <  meldingstijdGebruiker_ms)) {
    msg.payload = "startToonVraag";
    node.status({ text: tijd_nu + ": startToonVraag" });
    return msg;
}

// Wanneer is het tijd om een meldingen te sturen naar de gebruiker?
if ((tijd_nu_ms >= meldingstijdGebruiker_ms) &&
    (tijd_nu_ms < overtijd_ms) ) {
    msg.payload = "meldingsPeriodeGebruiker";
    node.status({ text: tijd_nu + ": meldingsPeriodeGebruiker" });
    return msg;
}

// Wanneer is het tijd om ook een email te sturen naar de contactpersonen?
if (tijd_nu_ms >= overtijd_ms) {
    msg.payload = "meldingsPeriodeVoorbij";
    node.status({ text: tijd_nu + ": meldingsPeriodeVoorbij" });
    return msg;
}

if (tijd_nu_ms == 0) {
    msg.payload = "middernacht";
    node.status({ text: tijd_nu + ": middernacht" });
    return msg;
}

return;

