global.set("currentState", "Idle");

var tijd_nu = global.get("getTime")();
node.status({ text: tijd_nu + " currentState=Idle"});

return msg;

let states = global.get("states");
var tijd_nu = global.get("getTime")();
let currentState = global.get("currentState");
let previousState = currentState;
global.set("previousState", previousState);

// Als iemand lang niet thuis is geweest wordt hij automatisch afgemeld:
let langNietThuis = 15; // minutes
// iPhones reageren slecht op (ar)ping. Alternatief: volg ook de naam van de iPhone in bluetoothctl scan on
if (global.get("PingCount") > 66) 
    langNietThuis = 30;

let trigger = msg.payload;

switch (currentState) {
    case states.IDLE: {
        if (trigger == "startToonVraag") currentState = states.TOONOKVRAAG;
        if (trigger == "meldingsPeriodeGebruiker") currentState = states.MELDGEBRUIKER;
        break;
    }
    case states.TOONOKVRAAGNIETTHUIS: {
        if (trigger == "isThuis") {
            let nietThuisSinds = flow.get("nietThuisSinds");
            let now = new Date();
            if (toMinutes(now) - toMinutes(nietThuisSinds) > langNietThuis) {
                currentState = states.ISOKAUTO;
            }
            else {
                currentState = states.TOONOKVRAAG;
            }
        }
        if (trigger == "middernacht") currentState = states.IDLE; 
        if (trigger == "meldingsPeriodeVoorbij") currentState = states.ISOKAUTO;
        break;
    }
    case states.TOONOKVRAAG: {
        if (trigger == "isNietThuis") {
            currentState = states.TOONOKVRAAGNIETTHUIS; 
            let now = new Date();
            flow.set("nietThuisSinds", now);
        }
        if (trigger == "middernacht") currentState = states.IDLE; 
        if (trigger == "jaPressed")   currentState = states.ISOK;
        if (trigger == "neePressed")  currentState = states.ISNOTOK;
        if (trigger == "meldingsPeriodeGebruiker") currentState = states.MELDGEBRUIKER;
        if (trigger == "meldingsPeriodeVoorbij")   currentState = states.OVERTIJD;
        break;
    }
    case states.MELDGEBRUIKERNIETTHUIS: {
        if (trigger == "isThuis") {
            let nietThuisSinds = flow.get("nietThuisSinds");
            let now = new Date();
            if (toMinutes(now) - toMinutes(nietThuisSinds) > langNietThuis) {
                currentState = states.ISOKAUTO; 
            }
            else {
                currentState = states.MELDGEBRUIKER; 
            }
        }
        if (trigger == "middernacht") currentState = states.IDLE; 
        if (trigger == "meldingsPeriodeVoorbij") currentState = states.ISOKAUTO;
        break;
    }
    case states.MELDGEBRUIKER: {
        if (trigger == "isNietThuis") {
            currentState = states.MELDGEBRUIKERNIETTHUIS; 
            let now = new Date();
            flow.set("nietThuisSinds", now);
        }
        if (trigger == "middernacht") currentState = states.IDLE; 
        if (trigger == "jaPressed")   currentState = states.ISOK;
        if (trigger == "neePressed")  currentState = states.ISNOTOK;
        if (trigger == "meldingsPeriodeVoorbij") currentState = states.OVERTIJD;
        break;
    }
    case states.ISOKAUTO: 
    case states.ISOK: 
    case states.ISNOTOK: {
        if (trigger == "middernacht") currentState = states.IDLE; 
        break;
    }
    case states.OVERTIJD: {
        if (trigger == "middernacht") currentState = states.IDLE;
        if (trigger == "jaPressed")   currentState = states.ISOK_OVERTIJD;
        if (trigger == "neePressed")  currentState = states.ISNOTOK_OVERTIJD;
        break;
    }
    case states.ISOK_OVERTIJD: {
        if (trigger == "middernacht") currentState = states.IDLE; 
        break;
    }
    case states.ISNOTOK_OVERTIJD: {
        if (trigger == "middernacht") currentState = states.IDLE; 
        break;
    }
}

global.set("currentState", currentState);

node.status({ text: tijd_nu + " State: " + currentState });

if (currentState != previousState) {
    msg.payload = currentState;
    return msg;
}
else
    return;

function toMinutes(date) {
    return date.getHours() * 60 + date.getMinutes();
}

var tijd_nu = global.get("getTime")();
let currentState = global.get("currentState");
let previousState = global.get("previousState");

let states = global.get("states");
switch (currentState) {
    case states.IDLE: {
        msg.reset = true;
        node.status({ text: tijd_nu + ", IDLE" });
        return [msg, null, null, null]; // stop met het sturen van berichten naar gebruiker
    }
    case states.TOONOKVRAAG: {
        node.status({ text: tijd_nu + ", TOONOKVRAAG" });
        msg.reset = true;
        return [msg, null, null, null];
    }
    case states.TOONOKVRAAGNIETTHUIS: {
        node.status({ text: tijd_nu + ", TOONOKVRAAGNIETTHUIS" });
        msg.reset = true;
        return [msg, null, null, null];
    }
    case states.MELDGEBRUIKERNIETTHUIS: {
        node.status({ text: tijd_nu + ", MELDGEBRUIKERNIETTHUIS" });
        msg.reset = true;
        return [msg, null, null, null];
    }
    case states.MELDGEBRUIKER: {
        node.status({ text: tijd_nu + ", MELDGEBRUIKER, delay (min): " + global.get("Herinnering") });
        msg.delay = global.get("Herinnering") * 60000;
        return [msg, null, null, null];
    }
    case states.ISOKAUTO:
    case states.ISOK: {
        node.status({ text: tijd_nu + ", reset timer, ISOK" });
        msg.reset = true;
        return [msg, null, null, null];
    }
    case states.ISNOTOK: {
        node.status({ text: tijd_nu + ", ISNOTOK" });
        msg.reset = true;
        return [msg, null, msg, null];
    }
    case states.OVERTIJD: {
        if (currentState != previousState) {
            node.status({ text: tijd_nu + ", OVERTIJD" });
            return [null, msg, null, null]; // Informeer contactpersonen
        }
        break;
    }
    case states.ISOK_OVERTIJD: {
        if (currentState != previousState) {
            node.status({ text: tijd_nu + ", ISOK_OVERTIJD" });
            msg.reset = true;
            msg.payload = "JA";
            return [msg, null, null, msg];
        }
        break;
    }
    case states.ISNOTOK_OVERTIJD: {
        if (currentState != previousState) {
            node.status({ text: tijd_nu + ", ISNOTOK_OVERTIJD" });
            msg.reset = true;
            msg.payload = "NEE";
            return [msg, null, null, msg];
        }
        break;
    }
}
return;

