global.set("tijdNaarMs", function (tijd) { // e.g. "09:15"
    let [h, m] = tijd.split(":").map(Number);
    return (h * 60 + m) * 60000;
});

global.set("getTime", function () {
    let now = new Date();
    return ('0' + now.getHours()).slice(-2) + ":" + ('0' + now.getMinutes()).slice(-2);
});

