function msToHM(ms) {
  const totalSeconds = Math.floor(ms / 1000);
  const minutes = Math.floor(totalSeconds / 60) % 60;
  const hours = Math.floor(totalSeconds / 3600);

  const pad = n => String(n).padStart(2, '0');
  return `${pad(hours)}:${pad(minutes)}`;
}

