function decimalChecksum(str) {
    let sum = 0;
    for (let i = 0; i < str.length; i++) {
        let digit = Number(str[i]);
        if (!isNaN(digit)) {
            sum += digit;
        }
    }
    return (sum % 100).toString().padStart(2, "0");
}

function verifyChecksum(str) {
    let firstPart = str.slice(0, -2);
    let lastTwo   = str.slice(-2);
    let checksum = decimalChecksum(firstPart);
    return (lastTwo == checksum);
}

function stringToDecimal(str) {
    if (typeof str !== "string") return null;

    // Spaties verwijderen
    str = str.replace(/\s+/g, "");

    let hex = "";
    for (let i = 0; i < str.length; i++) {
        hex += str.charCodeAt(i).toString(16).padStart(2, "0");
    }

    // Hex → decimaal getal (als string, want het kan groot zijn)
    return BigInt("0x" + hex).toString(10);
}

function decimalToString(decStr) {
    if (typeof decStr !== "string") return null;

    // Decimaal → BigInt → hex
    let hex = BigInt(decStr).toString(16);

    // Als hex lengte oneven is → opvullen
    if (hex.length % 2 === 1) {
        hex = "0" + hex;
    }

    let out = "";
    for (let i = 0; i < hex.length; i += 2) {
        const byte = parseInt(hex.substr(i, 2), 16);
        out += String.fromCharCode(byte);
    }

    return out;
}

function xorDecimal(decStr, xor) {
    const dec = BigInt(decStr);
    const xorVal = BigInt(xor);
    const result = dec ^ xorVal;
    return result.toString(10);
}

function addDashes(str) {
    return str.match(/.{1,2}/g).join("-");
}

function removeDashes(str) {
    return str.replace(/-/g, "");
}


/**
 * Bereken CRC32 over een hex-string.
 * Input: payload
 * Output: 32-bit unsigned integer
 */
function crc32Hex(hexStr) {
    // Opschonen
    hexStr = hexStr.replace(/[^0-9a-fA-F]/g, "");
    if (hexStr.length % 2 !== 0) {
        throw new Error("Hex-string moet een even aantal tekens hebben");
    }

    let crc = 0 ^ (-1);

    for (let i = 0; i < hexStr.length; i += 2) {
        const byte = parseInt(hexStr.substr(i, 2), 16);
        crc = (crc >>> 8) ^ crcTable[(crc ^ byte) & 0xFF];
    }

    return (crc ^ (-1)) >>> 0; // unsigned 32-bit
}

function encrypt(text, keyHex) {
    const key = parseInt(keyHex, 16);
    let out = "";
    for (let i = 0; i < text.length; i++) {
        out += String.fromCharCode(text.charCodeAt(i) ^ key);
    }
    return Buffer.from(out).toString("base64");
}

function decrypt(b64, keyHex) {
    const key = parseInt(keyHex, 16);
    const text = Buffer.from(b64, "base64").toString("utf8");
    let out = "";
    for (let i = 0; i < text.length; i++) {
        out += String.fromCharCode(text.charCodeAt(i) ^ key);
    }
    return out;
}


