const CryptoJS = global.get('crypto-js');

// Maak AES-256 sleutel van jouw korte key
function deriveKey(keyHex) {
    return CryptoJS.SHA256(CryptoJS.enc.Hex.parse(keyHex));
}

// Encrypt
function encryptAES256(text, keyHex) {
    const key = deriveKey(keyHex);
    const iv = CryptoJS.lib.WordArray.random(16);

    const encrypted = CryptoJS.AES.encrypt(text, key, {
        iv: iv,
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7
    });

    return iv.toString(CryptoJS.enc.Base64) + ":" + encrypted.toString();
}

// Decrypt
function decryptAES256(enc, keyHex) {
    const key = deriveKey(keyHex);
    const parts = enc.split(":");

    const iv = CryptoJS.enc.Base64.parse(parts[0]);
    const ciphertext = parts[1];

    const decrypted = CryptoJS.AES.decrypt(ciphertext, key, {
        iv: iv,
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7
    });

    return decrypted.toString(CryptoJS.enc.Utf8);
}

