function parseCpuInfo(cpuinfo) {
    // Extract the revision line
    const revisionMatch = cpuinfo.match(/Revision\s*:\s*([0-9a-fA-F]+)/);
    if (!revisionMatch) {
        return "";
    }

    const revision = revisionMatch[1].toLowerCase();

    // Mapping van revision codes naar modellen
    const revisionMap = {
        // --- Raspberry Pi 2 ---
        "a01041": "Raspberry Pi 2 Model B - revisie 1.1",
        // --- Raspberry Pi 3 ---
        "a02082": "Raspberry Pi 3 Model B",
        "a22082": "Raspberry Pi 3 Model B (Sony)",
        "a020d3": "Raspberry Pi 3 Model B+",
        "a020a0": "Raspberry Pi Compute Module 3",
        "a02100": "Raspberry Pi Compute Module 3+",

        // --- Raspberry Pi 4 ---
        "a03111": "Raspberry Pi 4 Model B (1GB)",
        "a03115": "Raspberry Pi 4 Model B+ (1GB) Rev 1.5",
        "b03111": "Raspberry Pi 4 Model B (2GB)",
        "b03115": "Raspberry Pi 4 Model B (2GB) Rev 1.5",
        "c03111": "Raspberry Pi 4 Model B (4GB)",
        "d03114": "Raspberry Pi 4 Model B (8GB)",

        // --- Raspberry Pi 400 ---
        "c03130": "Raspberry Pi 400",

        // --- Raspberry Pi Compute Module 4 ---
        "a03140": "Raspberry Pi Compute Module 4",
        "b03140": "Raspberry Pi Compute Module 4 (WiFi)",
        "c03140": "Raspberry Pi Compute Module 4 (Lite)",
        "d03140": "Raspberry Pi Compute Module 4 (WiFi + Lite)",

        // --- Raspberry Pi 5 ---
        "9023c0": "Raspberry Pi 5 (4GB)",
        "a023c0": "Raspberry Pi 5 (8GB)",
        "b023c0": "Raspberry Pi 5 (16GB)",

        // --- Raspberry Pi 5 Compute Module ---
        "c023c0": "Raspberry Pi Compute Module 5",
        "d023c0": "Raspberry Pi Compute Module 5 Lite"
    };

    const model = revisionMap[revision] || "Onbekende revision: " + revision;

return model;
}

