/**
 * Bereken CRC32 over een hex-string.
 * Input: payload
 * Output: 32-bit unsigned integer
 */
function crc32Hex(hexStr) {
    // Opschonen
    hexStr = hexStr.replace(/[^0-9a-fA-F]/g, "");
    if (hexStr.length % 2 !== 0) {
        throw new Error("Hex-string moet een even aantal tekens hebben");
    }

    let crc = 0 ^ (-1);

    for (let i = 0; i < hexStr.length; i += 2) {
        const byte = parseInt(hexStr.substr(i, 2), 16);
        crc = (crc >>> 8) ^ crcTable[(crc ^ byte) & 0xFF];
    }

    return (crc ^ (-1)) >>> 0; // unsigned 32-bit
}

