function checksum16(hexStr) {
    // Spaties verwijderen en lowercase
    hexStr = hexStr.replace(/\s+/g, "").toLowerCase();

    // Hex-string moet even aantal tekens hebben
    if (hexStr.length % 2 !== 0) {
        throw new Error("Hex-string moet een even aantal tekens hebben");
    }

    let sum = 0;

    for (let i = 0; i < hexStr.length; i += 2) {
        const byteHex = hexStr.substr(i, 2);
        const byteVal = parseInt(byteHex, 16);

        if (isNaN(byteVal)) {
            throw new Error("Ongeldige hex-waarde: " + byteHex);
        }

        sum = (sum + byteVal) & 0xFFFF; // 16-bit modulo
    }

    return sum.toString(16).padStart(4, "0"); // 4 hex chars
}
