const text = msg.payload;
node.status({ text: text });
const blocks = text.split(/(?=Device\s+[0-9A-F:]{17})/gi);

for (const block of blocks) {
    // MAC-adres
    const macMatch = block.match(/Device\s+([0-9A-F:]{17})/i);
    if (!macMatch) continue;

    // Naam
    const nameMatch = block.match(/Name:\s*(.+)/i);
    const name = nameMatch ? nameMatch[1].trim() : null;

    // Paired-status
    const pairedMatch = block.match(/Paired:\s*(yes|no)/i);
    const paired = pairedMatch ? pairedMatch[1].toLowerCase() : null;

    // Connected-status
    const connMatch = block.match(/Connected:\s*(yes|no)/i);
    const connected = connMatch ? connMatch[1].toLowerCase() : null;

    if (paired == "yes") {
        devices.push({
            mac: macMatch[1],
            name,
            paired,
            connected
        });
    }

    if (connected == "yes") {
        node.status({ text: "Connected: " + name });
        global.set("BluetoothMac", macMatch[1]);
        global.set("BluetoothConnectedName", name);
        global.set("BluetoothPaired", paired);
        global.set("BluetoothConnected", connected);
    }
    else {
        if (name == global.get("BluetoothConnectedName")) {
            global.set("BluetoothPaired", paired);
            global.set("BluetoothConnected", connected);
        }
    }
}

msg.payload = devices;
return msg;

